1	const PROCESSING_FEE = 5;
2	const BLOCK_SIZE = 3;
3	const BLOCK_PREMIUM = 60;
4	const CURSED_SURCHARGE_RATE = 0.5;
5	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
6	const HIGH_ENCHANTMENT_THRESHOLD = 5;
7	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
8	const LOYALTY_DISCOUNT_RATE = 0.2;
9	const LOYALTY_YEARS_THRESHOLD = 2;
10	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
11	
12	const BASE_PREMIUM: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	  rune: 25,
18	  moonstone: 25,
19	};
20	
21	const INSURANCE_VALUE: Record<string, number> = {
22	  sword: 1000,
23	  amulet: 600,
24	  staff: 800,
25	  potion: 400,
26	  rune: 250,
27	  moonstone: 250,
28	};
29	
30	const DEDUCTIBLE = 100;
31	
32	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
33	
34	function calculateItemPremium(item: any): { itemPremium: number; basePremium: number } {
35	  const basePremium = BASE_PREMIUM[item.type] ?? 0;
36	  const cursedSurcharge = item.cursed ? basePremium * CURSED_SURCHARGE_RATE : 0;
37	  const enchantmentSurcharge = item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD ? basePremium * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0;
38	  return { itemPremium: basePremium + cursedSurcharge + enchantmentSurcharge, basePremium };
39	}
40	
41	function computePremiumBreakdown(items: any[]): { itemPremiums: number; policyBase: number } {
42	  const componentCounts: Record<string, number> = {};
43	  let itemPremiums = 0;
44	  let policyBase = 0;
45	
46	  for (const item of items) {
47	    if (COMPONENT_TYPES.has(item.type)) {
48	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
49	    } else {
50	      if (!(item.type in BASE_PREMIUM)) {
51	        throw new Error(`Unknown item type: ${item.type}`);
52	      }
53	      const { itemPremium, basePremium } = calculateItemPremium(item);
54	      policyBase += basePremium;
55	      itemPremiums += itemPremium;
56	    }
57	  }
58	
59	  for (const [type, count] of Object.entries(componentCounts)) {
60	    const unitPrice = BASE_PREMIUM[type] ?? 0;
61	    const componentPremium = count === BLOCK_SIZE ? BLOCK_PREMIUM : count * unitPrice;
62	    itemPremiums += componentPremium;
63	    policyBase += count * unitPrice;
64	  }
65	
66	  return { itemPremiums, policyBase };
67	}
68	
69	function processClaim(
70	  step: any,
71	  policies: Record<number, any[]>,
72	  capRemaining: Record<number, number>,
73	): { payout: number; remainingCap: number } {
74	  const policyItems = policies[step.policy];
75	  const insuranceSum = policyItems.reduce(
76	    (sum: number, item: any) => sum + (INSURANCE_VALUE[item.type] ?? 0),
77	    0,
78	  );
79	  if (!(step.policy in capRemaining)) {
80	    capRemaining[step.policy] = insuranceSum * 2;
81	  }
82	  let totalPayout = 0;
83	  for (const damage of step.incident.damages) {
84	    const policyItem = policyItems.find((item: any) => item.type === damage.itemType);
85	    const reimbursement = policyItem?.enchantment >= 8 ? damage.amount * 0.5 : damage.amount;
86	    const payout = reimbursement - DEDUCTIBLE;
87	    totalPayout += Math.max(0, payout);
88	  }
89	  totalPayout = Math.min(totalPayout, capRemaining[step.policy]);
90	  totalPayout = Math.floor(totalPayout);
91	  capRemaining[step.policy] -= totalPayout;
92	  return { payout: totalPayout, remainingCap: capRemaining[step.policy] };
93	}
94	
95	function processQuote(
96	  step: any,
97	  index: number,
98	  yearsWithMHPCO: number,
99	): { premium: number } {
100	  const { itemPremiums, policyBase } = computePremiumBreakdown(step.items);
101	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
102	  const loyaltyDiscount =
103	    yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
104	      ? policyBase * LOYALTY_DISCOUNT_RATE
105	      : 0;
106	  const followUpDiscount =
107	    index > 0 ? policyBase * FOLLOW_UP_DISCOUNT_RATE : 0;
108	  const premium =
109	    Math.ceil(
110	      itemPremiums +
111	        firstInsuranceSurcharge -
112	        loyaltyDiscount -
113	        followUpDiscount,
114	    ) + PROCESSING_FEE;
115	  return { premium };
116	}
117	
118	export function processScenario(scenario: any): unknown {
119	  const policies: Record<number, any[]> = {};
120	  const capRemaining: Record<number, number> = {};
121	
122	  const results = scenario.steps.map((step: any, index: number) => {
123	    if (step.op === "claim") {
124	      return processClaim(step, policies, capRemaining);
125	    }
126	    policies[index] = step.items;
127	    return processQuote(step, index, scenario.customer.yearsWithMHPCO);
128	  });
129	  return { results };
130	}
