71	function processClaim(
72	  step: any,
73	  policies: Record<number, any[]>,
74	  capRemaining: Record<number, number>,
75	): { payout: number; remainingCap: number } {
76	  const policyItems = policies[step.policy];
77	  const insuranceSum = policyItems.reduce(
78	    (sum: number, item: any) => sum + (INSURANCE_VALUE[item.type] ?? 0),
79	    0,
80	  );
81	  if (!(step.policy in capRemaining)) {
82	    capRemaining[step.policy] = insuranceSum * 2;
83	  }
84	  let totalPayout = 0;
85	  for (const damage of step.incident.damages) {
86	    const policyItem = policyItems.find((item: any) => item.type === damage.itemType);
87	    const reimbursement = policyItem?.enchantment >= CLAIM_ENCHANTMENT_THRESHOLD ? damage.amount * CLAIM_ENCHANTMENT_REIMBURSEMENT_RATE : damage.amount;
88	    const payout = reimbursement - DEDUCTIBLE;
89	    totalPayout += Math.max(0, payout);
90	  }
91	  totalPayout = Math.min(totalPayout, capRemaining[step.policy]);
92	  totalPayout = Math.floor(totalPayout);
93	  capRemaining[step.policy] -= totalPayout;
94	  return { payout: totalPayout, remainingCap: capRemaining[step.policy] };
95	}
