97	function processQuote(
98	  step: any,
99	  index: number,
100	  yearsWithMHPCO: number,
101	): { premium: number } {
102	  const { itemPremiums, policyBase } = computePremiumBreakdown(step.items);
103	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
104	  const loyaltyDiscount =
105	    yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
106	      ? policyBase * LOYALTY_DISCOUNT_RATE
107	      : 0;
108	  const followUpDiscount =
109	    index > 0 ? policyBase * FOLLOW_UP_DISCOUNT_RATE : 0;
110	  const premium =
111	    Math.ceil(
112	      itemPremiums +
113	        firstInsuranceSurcharge -
114	        loyaltyDiscount -
115	        followUpDiscount,
116	    ) + PROCESSING_FEE;
117	  return { premium };
118	}
