120	export function processScenario(scenario: any): unknown {
121	  const policies: Record<number, any[]> = {};
122	  const capRemaining: Record<number, number> = {};
123	
124	  const results = scenario.steps.map((step: any, index: number) => {
125	    if (step.op === "claim") {
126	      return processClaim(step, policies, capRemaining);
127	    }
128	    policies[index] = step.items;
129	    return processQuote(step, index, scenario.customer.yearsWithMHPCO);
130	  });
131	  return { results };
132	}
